from pydantic import BaseModel, Field


class ReadParams(BaseModel):
    pass


class UpdateAndPushParams(BaseModel):
    latex_content: str = Field(..., min_length=1)
    commit_message: str = Field(default="AI update via Custom MCP")


class ReadBibliographyParams(BaseModel):
    bib_file: str = Field(default="references.bib", description="Name of the .bib file")


class UpdateAndPushBibliographyParams(BaseModel):
    bib_content: str = Field(..., min_length=1)
    bib_file: str = Field(default="references.bib", description="Name of the .bib file")
    commit_message: str = Field(default="AI bibliography update via Custom MCP")


TOOL_SCHEMAS = {
    "read_paper": ReadParams,
    "update_and_push_paper": UpdateAndPushParams,
    "read_bibliography": ReadBibliographyParams,
    "update_and_push_bibliography": UpdateAndPushBibliographyParams,
}
